   "out-data" : "update ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);position:relative;overflow:hidden;padding:6.5rem 0 5rem;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -32% auto;width:30rem;height:30rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 72%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.28em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.7rem,5vw,5rem);}\\\\n        .frawo-sub{color:var(--frawo-soft);font-size:1.1rem;line-height:1.65;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.6rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-outline{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-outline:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-hero-visual{display:grid;grid-template-columns:1.1fr .9fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-hero-main,.frawo-hero-card{border-radius:1.5rem;overflow:hidden;box-shadow:0 22px 52px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-hero-main img,.frawo-hero-card img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-hero-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;}\\\\n        .frawo-section{padding:4.75rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.7rem;padding:2.75rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-proof{border-radius:1.6rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-proof-grid img{width:100%;height:13rem;object-fit:cover;border-radius:1.15rem;box-shadow:0 14px 34px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-hero-visual{grid-template-columns:1fr;}.frawo-hero-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-proof-grid{grid-template-columns:1fr;}.frawo-proof-grid img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-hero-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Klare Technik, sichtbare Umsetzung und ein eigener Medienpfad fuer Projekte, die im Livebetrieb funktionieren muessen. FraWo verbindet Eventpraesenz, Website und Ablaufstabilitaet in einem sauberen Gesamtbild.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/contactus\\\\\">Kontakt</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digitale Betriebsablaeufe</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; Automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; Medienpraesenz</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-hero-visual\\\\\">\\\\n                <div class=\\\\\"frawo-hero-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Hauptmotiv\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-hero-side\\\\\">\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo Detailmotiv 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo Detailmotiv 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digitale Ordnung</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kontrollierte Arbeitsablaeufe mit Odoo, Nextcloud und Paperless statt Zettelchaos, Medienbruch und blindem Tool-Wildwuchs.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website mit Rueckgrat</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kein austauschbarer Auftritt, sondern eine sichtbare Linie mit Kontaktpfad, klaren Informationen und technischer Substanz im Hintergrund.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; Event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Praesenz, Zuspielung und mediale Sichtbarkeit bleiben nicht Nebenschauplatz, sondern Teil einer wiedererkennbaren Handschrift.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Anpacker mit Koepfchen, sauber bis in den Betriebspfad.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo verbindet klare Umsetzung mit technischer Praezision: Infrastruktur, Website, Dokumente und Kommunikation greifen kontrolliert ineinander statt sich gegenseitig zu blockieren.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Analyse:</strong> Erst den echten Zustand lesen, dann bauen.</li>\\\\n                  <li><strong>Aufbau:</strong> Klare Systeme, klare Rollen, klare Rueckwege.</li>\\\\n                  <li><strong>Livegang:</strong> Nutzbar fuer Alltag, Team und sichtbare Praesentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">Wofuer FraWo steht</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Klartext statt Blendwerk.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">Wir moegen Loesungen, die im Alltag tragen: nachvollziehbar, robust und ohne kuenstlich aufgeblasene Komplexitaet. Genau deshalb bleibt diese Seite fokussiert und zeigt zugleich echte Bilder aus dem FraWo-Umfeld.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Die erste Wirkung soll ehrlich sein: keine Stockbilder, keine Behauptungen, sondern sichtbare Praxis und ein direkter Draht fuer das naechste Projekt.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Bildstrecke</div>\\\\n                <div class=\\\\\"frawo-proof-grid\\\\\">\\\\n                  <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo Galerie 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo Galerie 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo Galerie 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Kontakt</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Projekt, Idee oder Rueckfrage?</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">Am schnellsten erreichst du FraWo aktuell per Mail. Fuer kurze Rueckfragen ist der direkte Telefonpfad offen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Direkter Einstieg</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Mail mit Ort, Termin, Zielbild und technischer Lage reicht fuer den ersten Aufschlag. Danach ziehen wir den passenden Weg auf.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\", \"en_US\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);position:relative;overflow:hidden;padding:6.5rem 0 5rem;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -32% auto;width:30rem;height:30rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 72%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.28em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.7rem,5vw,5rem);}\\\\n        .frawo-sub{color:var(--frawo-soft);font-size:1.1rem;line-height:1.65;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.6rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-outline{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-outline:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-hero-visual{display:grid;grid-template-columns:1.1fr .9fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-hero-main,.frawo-hero-card{border-radius:1.5rem;overflow:hidden;box-shadow:0 22px 52px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-hero-main img,.frawo-hero-card img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-hero-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;}\\\\n        .frawo-section{padding:4.75rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.7rem;padding:2.75rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-proof{border-radius:1.6rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-proof-grid img{width:100%;height:13rem;object-fit:cover;border-radius:1.15rem;box-shadow:0 14px 34px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-hero-visual{grid-template-columns:1fr;}.frawo-hero-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-proof-grid{grid-template-columns:1fr;}.frawo-proof-grid img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-hero-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Clear technology, visible execution and a dedicated media path for projects that need to hold up under live conditions. FraWo connects event presence, website and operational stability in one coherent picture.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Project%20Request%20FraWo\\\\\">Start a project</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/contactus\\\\\">Contact</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digital operations</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; media presence</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-hero-visual\\\\\">\\\\n                <div class=\\\\\"frawo-hero-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo main image\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-hero-side\\\\\">\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo detail image 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo detail image 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digital order</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Controlled workflows with Odoo, Nextcloud and Paperless instead of scattered notes, media breaks and random tool chaos.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website with backbone</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Not a generic presence, but a visible line with direct contact paths, clear information and technical substance behind it.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Presence, playback and media visibility are part of a recognisable signature, not an afterthought.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">How we work</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Hands-on people with technical discipline.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo combines clear execution with technical precision: infrastructure, website, documents and communication are built to work together instead of blocking each other.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Read first:</strong> understand the real situation before changing it.</li>\\\\n                  <li><strong>Build:</strong> clear systems, clear roles, clear rollback paths.</li>\\\\n                  <li><strong>Go live:</strong> usable for daily work, teams and presentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">What FraWo stands for</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Straight talk instead of empty gloss.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">We prefer solutions that hold up in real work: understandable, robust and free of inflated complexity. That is why this page stays focused and still uses real imagery from the FraWo context.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">The first impression should be honest: no stock photography, no empty claims, just visible practice and a direct path for the next project.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Image strip</div>\\\\n                <div class=\\\\\"frawo-proof-grid\\\\\">\\\\n                  <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo gallery 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo gallery 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo gallery 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Contact</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Project, idea or question?</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">The fastest path is currently email. For short questions, the direct phone path is open.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Direct start</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">A mail with location, date, target picture and technical situation is enough for the first pass. From there we pull the right path into place.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3636;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Contact Us\\\\\" t-name=\\\\\"website.contactus\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{--frawo-forest:#064e3b;--frawo-forest-dark:#052e16;--frawo-accent:#a855f7;--frawo-ink:#0f172a;--frawo-soft:#475569;}\\\\n        .frawo-contact-page{background:linear-gradient(180deg,#f8fffb 0%,#ffffff 100%);}\\\\n        .frawo-contact-page .container{position:relative;z-index:1;}\\\\n        .frawo-kicker{letter-spacing:.22em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-contact-hero{position:relative;overflow:hidden;padding:6rem 0 4.5rem;background:radial-gradient(circle at 75% 18%, rgba(168,85,247,.16), transparent 25%),linear-gradient(135deg,#052e16 0%,#064e3b 58%,#14532d 100%);color:#ecfdf5;}\\\\n        .frawo-contact-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -35% auto;width:26rem;height:26rem;border-radius:50%;background:radial-gradient(circle,#a855f744 0%,#a855f700 72%);}\\\\n        .frawo-contact-title{font-weight:900;line-height:.96;font-size:clamp(2.5rem,5vw,4.5rem);}\\\\n        .frawo-contact-sub{font-size:1.08rem;line-height:1.7;max-width:40rem;color:#dcfce7;}\\\\n        .frawo-contact-photo{border-radius:1.6rem;overflow:hidden;box-shadow:0 22px 60px rgba(15,23,42,.2);}\\\\n        .frawo-contact-photo img{width:100%;height:100%;object-fit:cover;display:block;min-height:19rem;}\\\\n        .frawo-contact-section{padding:4.75rem 0;}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.5rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.08);}\\\\n        .frawo-contact-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-contact-card p,.frawo-contact-card li{color:var(--frawo-soft);}\\\\n        .frawo-contact-cta{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-contact-cta:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-contact-list{list-style:none;padding:0;margin:0;display:grid;gap:.9rem;}\\\\n        .frawo-contact-list li{display:flex;gap:.8rem;align-items:flex-start;}\\\\n        .frawo-contact-list li:before{content:\\\\\"\\\\\";margin-top:.45rem;width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);flex:0 0 auto;}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-contact-page frawo-contact-hero\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:#c4b5fd;\\\\\">Kontakt</div>\\\\n              <h1 class=\\\\\"frawo-contact-title mb-3\\\\\">Projektstart ohne Umwege.</h1>\\\\n              <p class=\\\\\"frawo-contact-sub mb-4\\\\\">Wenn eine Veranstaltung, ein Techniksetup oder eine Event-Seite sauber aufgesetzt werden soll, reicht eine klare Anfrage. FraWo antwortet lieber konkret als kuenstlich aufgeblasen.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                <a class=\\\\\"btn btn-light btn-lg\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">info@frawo-tech.de</a>\\\\n                <a class=\\\\\"btn btn-outline-light btn-lg\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"frawo-contact-photo\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Eventkontakt Bild\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-contact-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Mail</h3><p class=\\\\\"mb-3\\\\\">Der schnellste Weg fuer Anfragen, Termine, Material und erste Eckdaten.</p><p class=\\\\\"mb-0\\\\\"><a href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a></p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Telefon</h3><p class=\\\\\"mb-3\\\\\">Wenn etwas schnell geklaert werden muss oder der Live-Termin naeher rueckt.</p><p class=\\\\\"mb-0\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a></p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Standort</h3><p class=\\\\\"mb-3\\\\\">FraWo arbeitet von Weissensberg aus und betreut Einsaetze mit klarer Technik- und Kommunikationslinie.</p><p class=\\\\\"mb-0\\\\\">Rothkreuz 14<br/>88138 Weissensberg</p></div></div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-contact-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Typische Themen</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Wobei FraWo direkt sinnvoll wird</h2>\\\\n              <ul class=\\\\\"frawo-contact-list\\\\\">\\\\n                <li>Technische Betreuung fuer Veranstaltung, Livestream oder Medienbuehne.</li>\\\\n                <li>Event-Seite mit Kontaktpfad, Updates und klarer Information fuer Team oder Publikum.</li>\\\\n                <li>Signalweg, Zuspielung und Ablauf muessen an einem Termin zuverlaessig stehen.</li>\\\\n                <li>Ein Ansprechpartner soll Umsetzung, Kommunikation und Nachlauf zusammenhalten.</li>\\\\n              </ul>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Fuer die erste Mail hilfreich</h3>\\\\n                <ul class=\\\\\"frawo-contact-list\\\\\">\\\\n                  <li>Wann und wo findet der Termin statt?</li>\\\\n                  <li>Was soll technisch und kommunikativ stehen?</li>\\\\n                  <li>Welche Rolle spielt die Website oder das Update-Fenster?</li>\\\\n                  <li>Gibt es feste Risiken, Fristen oder Ansprechpartner?</li>\\\\n                </ul>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3 mt-4\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-contact-cta\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                  <a class=\\\\\"btn btn-outline-secondary\\\\\" href=\\\\\"/\\\\\">Zur Startseite</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3637;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);position:relative;overflow:hidden;padding:6.5rem 0 5rem;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -32% auto;width:30rem;height:30rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 72%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.28em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.7rem,5vw,5rem);}\\\\n        .frawo-sub{color:var(--frawo-soft);font-size:1.1rem;line-height:1.65;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.6rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-outline{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-outline:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-hero-visual{display:grid;grid-template-columns:1.1fr .9fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-hero-main,.frawo-hero-card{border-radius:1.5rem;overflow:hidden;box-shadow:0 22px 52px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-hero-main img,.frawo-hero-card img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-hero-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;}\\\\n        .frawo-section{padding:4.75rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.7rem;padding:2.75rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-proof{border-radius:1.6rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-proof-grid img{width:100%;height:13rem;object-fit:cover;border-radius:1.15rem;box-shadow:0 14px 34px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-hero-visual{grid-template-columns:1fr;}.frawo-hero-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-proof-grid{grid-template-columns:1fr;}.frawo-proof-grid img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-hero-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Klare Technik, sichtbare Umsetzung und ein eigener Medienpfad fuer Projekte, die im Livebetrieb funktionieren muessen. FraWo verbindet Eventpraesenz, Website und Ablaufstabilitaet in einem sauberen Gesamtbild.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/contactus\\\\\">Kontakt</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digitale Betriebsablaeufe</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; Automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; Medienpraesenz</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-hero-visual\\\\\">\\\\n                <div class=\\\\\"frawo-hero-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Hauptmotiv\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-hero-side\\\\\">\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo Detailmotiv 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo Detailmotiv 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digitale Ordnung</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kontrollierte Arbeitsablaeufe mit Odoo, Nextcloud und Paperless statt Zettelchaos, Medienbruch und blindem Tool-Wildwuchs.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website mit Rueckgrat</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Kein austauschbarer Auftritt, sondern eine sichtbare Linie mit Kontaktpfad, klaren Informationen und technischer Substanz im Hintergrund.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; Event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Praesenz, Zuspielung und mediale Sichtbarkeit bleiben nicht Nebenschauplatz, sondern Teil einer wiedererkennbaren Handschrift.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Anpacker mit Koepfchen, sauber bis in den Betriebspfad.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo verbindet klare Umsetzung mit technischer Praezision: Infrastruktur, Website, Dokumente und Kommunikation greifen kontrolliert ineinander statt sich gegenseitig zu blockieren.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Analyse:</strong> Erst den echten Zustand lesen, dann bauen.</li>\\\\n                  <li><strong>Aufbau:</strong> Klare Systeme, klare Rollen, klare Rueckwege.</li>\\\\n                  <li><strong>Livegang:</strong> Nutzbar fuer Alltag, Team und sichtbare Praesentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">Wofuer FraWo steht</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Klartext statt Blendwerk.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">Wir moegen Loesungen, die im Alltag tragen: nachvollziehbar, robust und ohne kuenstlich aufgeblasene Komplexitaet. Genau deshalb bleibt diese Seite fokussiert und zeigt zugleich echte Bilder aus dem FraWo-Umfeld.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Die erste Wirkung soll ehrlich sein: keine Stockbilder, keine Behauptungen, sondern sichtbare Praxis und ein direkter Draht fuer das naechste Projekt.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Bildstrecke</div>\\\\n                <div class=\\\\\"frawo-proof-grid\\\\\">\\\\n                  <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo Galerie 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo Galerie 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo Galerie 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Kontakt</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Projekt, Idee oder Rueckfrage?</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">Am schnellsten erreichst du FraWo aktuell per Mail. Fuer kurze Rueckfragen ist der direkte Telefonpfad offen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Direkter Einstieg</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Mail mit Ort, Termin, Zielbild und technischer Lage reicht fuer den ersten Aufschlag. Danach ziehen wir den passenden Weg auf.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\", \"en_US\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-hero{background:linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);position:relative;overflow:hidden;padding:6.5rem 0 5rem;}\\\\n        .frawo-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -32% auto;width:30rem;height:30rem;border-radius:50%;background:radial-gradient(circle,#a855f733 0%,#a855f700 72%);pointer-events:none;}\\\\n        .frawo-eyebrow{letter-spacing:.28em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.7rem,5vw,5rem);}\\\\n        .frawo-sub{color:var(--frawo-soft);font-size:1.1rem;line-height:1.65;max-width:42rem;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.6rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-outline{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-outline:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-hero-visual{display:grid;grid-template-columns:1.1fr .9fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-hero-main,.frawo-hero-card{border-radius:1.5rem;overflow:hidden;box-shadow:0 22px 52px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-hero-main img,.frawo-hero-card img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-hero-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;}\\\\n        .frawo-section{padding:4.75rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.7rem;padding:2.75rem;}\\\\n        .frawo-band a{color:#ffffff;}\\\\n        .frawo-kicker{color:#a7f3d0;font-weight:700;letter-spacing:.18em;text-transform:uppercase;font-size:.8rem;}\\\\n        .frawo-proof{border-radius:1.6rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-proof-grid img{width:100%;height:13rem;object-fit:cover;border-radius:1.15rem;box-shadow:0 14px 34px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.45rem;background:#ffffff;box-shadow:0 20px 48px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-hero-visual{grid-template-columns:1fr;}.frawo-hero-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-proof-grid{grid-template-columns:1fr;}.frawo-proof-grid img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-hero-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n\\\\n      <section class=\\\\\"frawo-hero\\\\\">\\\\n        <div class=\\\\\"container position-relative\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">FraWo GbR</div>\\\\n              <h1 class=\\\\\"frawo-title mb-4\\\\\">Smart Media &amp; Event</h1>\\\\n              <p class=\\\\\"frawo-sub mb-4\\\\\">Clear technology, visible execution and a dedicated media path for projects that need to hold up under live conditions. FraWo connects event presence, website and operational stability in one coherent picture.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Project%20Request%20FraWo\\\\\">Start a project</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"/contactus\\\\\">Contact</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Digital operations</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Web &amp; automation</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Radio &amp; media presence</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-hero-visual\\\\\">\\\\n                <div class=\\\\\"frawo-hero-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo main image\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-hero-side\\\\\">\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo detail image 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-hero-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo detail image 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">01</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Digital order</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Controlled workflows with Odoo, Nextcloud and Paperless instead of scattered notes, media breaks and random tool chaos.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">02</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Website with backbone</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Not a generic presence, but a visible line with direct contact paths, clear information and technical substance behind it.</p>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\">\\\\n              <div class=\\\\\"card frawo-card p-4\\\\\">\\\\n                <div class=\\\\\"frawo-number mb-3\\\\\">03</div>\\\\n                <h3 class=\\\\\"h4 mb-3\\\\\">Media &amp; event</h3>\\\\n                <p class=\\\\\"mb-0\\\\\">Presence, playback and media visibility are part of a recognisable signature, not an afterthought.</p>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row align-items-center g-4\\\\\">\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\">How we work</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Hands-on people with technical discipline.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo combines clear execution with technical precision: infrastructure, website, documents and communication are built to work together instead of blocking each other.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <ul class=\\\\\"list-unstyled mb-0 d-grid gap-3\\\\\">\\\\n                  <li><strong>Read first:</strong> understand the real situation before changing it.</li>\\\\n                  <li><strong>Build:</strong> clear systems, clear roles, clear rollback paths.</li>\\\\n                  <li><strong>Go live:</strong> usable for daily work, teams and presentation.</li>\\\\n                </ul>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-eyebrow mb-3\\\\\">What FraWo stands for</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Straight talk instead of empty gloss.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">We prefer solutions that hold up in real work: understandable, robust and free of inflated complexity. That is why this page stays focused and still uses real imagery from the FraWo context.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">The first impression should be honest: no stock photography, no empty claims, just visible practice and a direct path for the next project.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Image strip</div>\\\\n                <div class=\\\\\"frawo-proof-grid\\\\\">\\\\n                  <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo gallery 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo gallery 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                  <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo gallery 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:var(--frawo-accent);\\\\\">Contact</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Project, idea or question?</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">The fastest path is currently email. For short questions, the direct phone path is open.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Direct start</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">A mail with location, date, target picture and technical situation is enough for the first pass. From there we pull the right path into place.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-outline\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3644;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<data inherit_id=\\\\\"website.layout\\\\\" name=\\\\\"Default\\\\\" active=\\\\\"True\\\\\">\\\\n  <xpath expr=\\\\\"//div[@id=''footer'']\\\\\" position=\\\\\"replace\\\\\">\\\\n    <div id=\\\\\"footer\\\\\" class=\\\\\"oe_structure oe_structure_solo\\\\\" t-ignore=\\\\\"true\\\\\" t-if=\\\\\"not no_footer\\\\\">\\\\n      <section class=\\\\\"s_text_block pt40 pb24\\\\\" data-snippet=\\\\\"s_text_block\\\\\" data-name=\\\\\"Text\\\\\" style=\\\\\"background:#052e16; color:#ecfdf5;\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4 align-items-start\\\\\">\\\\n            <div class=\\\\\"col-lg-4\\\\\">\\\\n              <h4 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#ffffff;\\\\\">FraWo GbR</h4>\\\\n              <p class=\\\\\"mb-0\\\\\">Eventdienstleistung mit technischer Disziplin: Medientechnik, Ablaufsteuerung, Website- und Informationspfade fuer Auftritte, die live sauber stehen muessen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-3\\\\\">\\\\n              <h5 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#a7f3d0;\\\\\">Direktwege</h5>\\\\n              <ul class=\\\\\"list-unstyled mb-0\\\\\">\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/\\\\\" style=\\\\\"color:#ffffff;\\\\\">Startseite</a></li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/contactus\\\\\" style=\\\\\"color:#ffffff;\\\\\">Kontakt</a></li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/privacy\\\\\" style=\\\\\"color:#ffffff;\\\\\">Datenschutz</a></li>\\\\n                <li><a href=\\\\\"mailto:info@frawo-tech.de\\\\\" style=\\\\\"color:#ffffff;\\\\\">Projekt anfragen</a></li>\\\\n              </ul>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <h5 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#a7f3d0;\\\\\">Kontakt</h5>\\\\n              <ul class=\\\\\"list-unstyled mb-0\\\\\">\\\\n                <li class=\\\\\"mb-2\\\\\">Rothkreuz 14, 88138 Weissensberg</li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\" style=\\\\\"color:#ffffff;\\\\\">+49 151 55243164</a></li>\\\\n                <li><a href=\\\\\"mailto:info@frawo-tech.de\\\\\" style=\\\\\"color:#ffffff;\\\\\">info@frawo-tech.de</a></li>\\\\n              </ul>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </xpath>\\\\n</data>\\\\n\"}' where id=4405;\n",
